// HMAC-SHA256 validation of the inbound webhook (R-02: fail-closed).
const crypto = require('crypto');
const secret = $env['HEALTH_CHECK_WEBHOOK_SECRET'] ?? '';
if (!secret) throw new Error('HEALTH_CHECK_WEBHOOK_SECRET missing — fail-closed (R-02)');
const sig = $input.first().headers['x-signature-256'] ?? '';
const rawBody = $input.first().binary?.data?.data
  ? Buffer.from($input.first().binary.data.data, 'base64').toString('utf8')
  : JSON.stringify($input.first().json);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
if (!sig || sig.length !== expected.length || !crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected))) {
  throw new Error('Invalid HMAC — dropping payload (R-02)');
}

const body = $input.first().json ?? {};
const chat_id = body.chat_id ? String(body.chat_id) : '';

return [{
  json: {
    intent: 'health status check',
    chat_id,
    user_id: String(body.user_id ?? ''),
    timestamp: new Date().toISOString(),
    metadata: {}
  }
}];

// HMAC-SHA256 over the exact body string the Router will read (ADR-0003).
const crypto = require('crypto');
const p = $input.first().json;
const bodyObj = {
  intent: p.intent,
  chat_id: p.chat_id,
  user_id: p.user_id,
  timestamp: p.timestamp,
  metadata: p.metadata,
};
const bodyStr = JSON.stringify(bodyObj);
const secret = $env['SKILLS_ROUTER_SECRET'] ?? '';
if (!secret) throw new Error('SKILLS_ROUTER_SECRET missing — fail-closed (R-02)');
const sig = 'sha256=' + crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
return [{ json: { _bodyStr: bodyStr, _sig: sig, _chat_id: p.chat_id } }];

// Combine the two parallel probes into a single Telegram-friendly status line.
// Reuses the same response-shape parsing as OpenRouterBudgetGate.getCreditsBalance
// (src/agent/index.ts:254-257): remaining = total_credits - total_usage.
const routerProbe = $('Probe Router /health').first();
const creditsProbe = $('Probe OpenRouter /credits').first();

function routerOk() {
  if (routerProbe?.json?.error) return false;
  return routerProbe?.json?.status === 'ok';
}

function creditsRemaining() {
  const data = creditsProbe?.json?.data;
  if (!data) return null;
  const totalCredits = Number(data.total_credits ?? 0);
  const totalUsage = Number(data.total_usage ?? 0);
  return totalCredits - totalUsage;
}

const router = routerOk() ? 'ok' : 'DOWN';
const remaining = creditsRemaining();
const openrouter = remaining === null ? 'DOWN' : `$${remaining.toFixed(2)}`;
const chat_id = $('Compute Skills Router HMAC').first().json._chat_id;
const timestamp = new Date().toISOString();

return [{
  json: {
    chat_id,
    text: `Health: router=${router} openrouter=${openrouter} ts=${timestamp}`,
    router,
    openrouter,
    remaining_usd: remaining,
    timestamp
  }
}];
